import { BeSkill, Options } from '@be/be-framework';
import jibo = require('jibo');
import Analytics from './analytics/Analytics';
import CardSelector from './CardSelector';
import CardMenuView from './views/CardMenuView';
import CardDisplay from './CardDisplay';
import CardData from './CardData';

let mainFlow: any = require('./flows/main');

export default class FriendlyTips extends BeSkill {

    // For tests
    public static CardMenuView = CardMenuView;
    public static CardSelector = CardSelector;
    public static CardDisplay = CardDisplay;
    public static CardData = CardData;

    public flow: any;
    public blackboard: any;
    public cardsShown: number = null;
    public analytics: Analytics;
    private flowOverrides:any = null;
    private cardSelector:CardSelector;
    private cardDisplay:CardDisplay;

    /**
     * Template skill constructor
     * @constructor
     * @param {String} [assetPack=''] The asset pack if loading from Be
     */
    constructor(assetPack?: Options) {
        super(assetPack);
        this.analytics = new Analytics(this);
    }

    preload(done: (err?: any) => void): void {
        this.cardSelector = new CardSelector(this);
        this.cardSelector.init(()=>{
            done();
        });
    }

    /**
     * Start the skill
     * @method open
     */
    open(result?: any, refresh?: boolean) {
        this.log.info('opening skill');
        jibo.face.views.creator.registerClass(CardMenuView);
        if (!result) {
            result = { nlu: { intent: 'whatCanIDo' } };
        }
        this.log.debug('nlu:', result.nlu);

        if (refresh) {
            this._cleanup(()=>{
                this.runFlow(result, refresh);
            });
        }
        else{
            this.runFlow(result, refresh);
        }
    }

    runFlow(result: any, refresh?: boolean){
        this.cardsShown = 0;
        this.cardDisplay = new CardDisplay(this.log, this.cardSelector);
        this.blackboard = {
            assetPack: this.assetPack,
            cardDisplay: this.cardDisplay,
            log: this.log
        };

        const options = Object.assign({
                enableLogging: true,
                assetPack: this.assetPack,
                blackboard: this.blackboard,
                params: {
                    result: result,
                    refresh: !!refresh
                }
            },
            this.flowOverrides);

        this.flow = jibo.flow.run(mainFlow, options, (err, status) => {
            if (status === jibo.bt.Status.INTERRUPTED) {
                return;
            }
            this.exit();
        });
    }

    /**
     * Stop and unload the skill
     * @method close
     */
    close(done: () => void): void {
        this.log.info('closing skill');
        jibo.face.views.creator.unregisterClass('CardMenuView');
        this._cleanup(()=>{
            if (this.cardSelector) {
                this.cardSelector.destroy();
                this.cardSelector = null;
            }
            done();
        });
    }

    _cleanup(done: () => void) {
        if(this.cardsShown !== null){
            this.analytics.thingsDone(this.cardsShown);
            this.cardsShown = null;
        }

        if (this.flow) {
            this.flow.stopAndDestroy().then(() => {
                if(this.cardDisplay){
                    this.cardDisplay.destroy();
                    this.cardDisplay = null;
                }
                this.flow = null;
                if(jibo.face.views.currentView && jibo.face.views.currentView.id !== 'eyeView'){
                    jibo.face.views.changeView(
                        {
                            removeAll: true,
                            leaveEmpty: true
                        },
                        () => {
                            done();
                        }, //onComplete
                        (err) => {
                            this.log.error(err);
                            done();
                        } //onFail
                    );
                }
                else{
                    jibo.face.views.forceEyeView(() => {
                        done();
                    },
                    null, // onLoaded callback
                    null, // use default transitionOpen
                    null, // use default transitionClose
                    () => {
                        this.log.error('Error removing view, calling done anyway');
                        done();
                    })
                }
            });
        }
        else{
            done();
        }
    }
}
