import Category from './Category';
import jibo = require('jibo');
import FriendlyTips from './FriendlyTips';

let HJ:string = "Hey Jibo";

export default class CardData {
    public id:string;
    public speech:string;
    public featured:boolean;
    public seen:boolean;
    public categoryName:string;
    public categoryId:string;
    public rootNode:jibo.kb.Node;
    private _text:string;
    private _background:string;
    private log:typeof jibo.log;
    private _skill:FriendlyTips;

    constructor(data:any, seen:boolean, category:Category){
        this.id = data.id;
        this._text = data.text;
        this.speech = data.speech || data.text;
        this.featured = !!data.featured;
        this.seen = seen;
        this._background = category.background;
        this.categoryName = category.name;
        this.categoryId = category.id;
        this.rootNode = category.rootNode;
        this.log = category.log;
        this._skill = category.skill;
    }

    public get text():string{
        return `${HJ}, ${this._text}`;
    }

    public get background():string{
        return `assets/backgrounds/${this._background}`;
    }

    public markSeen(done?:()=>void){
        if(this._skill && this._skill.cardsShown !== null){
            this._skill.cardsShown++;
            this._skill.analytics.cardShown(this._text);
        }
        this.seen = true;
        this.rootNode.data.seen[this.categoryId][this.id] = Date.now();
        this.rootNode.save((err)=>{
            if(err && this.log){
                this.log.warn('failed to save card seen data: ', err);
            }
            if(done){
                done();
            }
        });
    }

    public destroy(){
        this.id = null;
        this._text = null;
        this.speech = null;
        this.featured = null;
        this.seen = null;
        this._background = null;
        this.categoryName = null;
        this.categoryId = null;
        this.rootNode = null;
        this.log = null;
        this._skill = null;
    }

}
