import jibo = require('jibo');
import Component = jibo.rendering.gui.Component;
import Label = jibo.rendering.gui.components.Label;
import List = jibo.rendering.gui.components.List;
import ListOptions = jibo.rendering.gui.components.ListOptions;
import MenuView = jibo.rendering.gui.views.MenuView;
import MenuButton = jibo.rendering.gui.components.MenuButton;
import ElementGroup = jibo.rendering.gui.components.ElementGroup;

const log = jibo.log.createChild('Be.FriendlyTips.CardMenuView');
const ELEMENT_WIDTH = 1016;
const ELEMENT_HEIGHT = 520;
const ELEMENTS_PER_PAGE = 1;

export default class CardMenuView extends MenuView {

    private _buttonLabelsText: string[] = [];

    constructor() {
        super();
    }

    public static get DEFAULT_TYPE():string {return 'CardMenuView';}

    public applyData():void {
        // create List
        this._list = new List();
        this.addComponent(this._list);

        // create components for list
        this.createListComponents(this._list);

        // create config for List
        const listConfig:ListOptions = (this._viewConfig) ? Object.assign({}, this._viewConfig) : {};
        listConfig.id = 'list';
        listConfig.type = List.DEFAULT_TYPE;
        if (!listConfig.elementsPerPage) {
            listConfig.elementsPerPage = ELEMENTS_PER_PAGE;
        }
        if (!listConfig.elementDimensions) {
            listConfig.elementDimensions = {
                width: ELEMENT_WIDTH,
                height: ELEMENT_HEIGHT
            };
        }
        // remove unneeded variables that may have been carried over from viewConfig
        delete (<any>listConfig).title;
        delete (<any>listConfig).assets;
        delete (<any>listConfig).list;

        // apply list config to list
        this._list.assignConfig(listConfig);

        // create menu button labels, if menu buttons specify labels
        this._buttonLabels = [];
        let buttonLabel:Label;
        for (let i:number = 0; i < ELEMENTS_PER_PAGE; i++) {
            buttonLabel = new Label();
            buttonLabel.id = 'buttonLabel' + i;
            buttonLabel.text = this.componentConfigs[0].componentConfigs[i].label;
            buttonLabel.style = Label.createFontStyle(45,'Proxima Nova Light','#FFFFFF','', 'center');
            buttonLabel.bounds = {width:listConfig.elementDimensions.width, height:listConfig.elementDimensions.height};
            this.addComponent(buttonLabel);
            this._buttonLabels.push(buttonLabel);
        }
    }

    protected createListComponents(list:List):void {
        if(this._viewConfig) {
            const defaultElementData = this._viewConfig.listDefault || {};
            const componentType:string = defaultElementData.elementGroupType || ElementGroup.DEFAULT_TYPE;
            if (!defaultElementData.type) {
                defaultElementData.type = componentType;
            }
            const configs = this.componentConfigs[0].componentConfigs;
            this._buttonLabelsText = configs.map((config) => config.label);
            list.createComponentsFromConfigs(configs, defaultElementData);
        }
        else {
            log.warn('createListComponents() this._viewConfig was not defined, but is required.');
        }
    }

    protected updateButtonLabels(labelRemovalNeeded:boolean = false, playTransition:boolean = true, duration:number = 200):void {
        if (!this._buttonLabels) {
            return;
        }
        // flag says that we need to remove last label in list which then reqires a reposition of remaining labels
        if (labelRemovalNeeded) {
            let component:Component = this.removeComponent(this._buttonLabels.pop());
            if (component) {
                component.destroy();
                component = null;
            }
        }
        this.positionButtonLabels();
        // check currently visible buttons
        const buttonComponents:Array<Component> = this._list.getElementsByPage();
        const length:number = buttonComponents.length;
        if(playTransition) {
            for( let i:number = 0; i < length; i++) {
                let buttonLabel:Label = this._buttonLabels[i];
                buttonLabel.text = this._buttonLabelsText[this._list.pageIndex];
                // transition button
                if(buttonLabel.display.alpha === 1) {
                    buttonLabel.close(() => {
                        buttonLabel.open(null, null, duration);
                    }, null, duration);
                }
                else{
                    buttonLabel.open(null, null, duration);
                }
            }
        }
        else{
            for( let i:number = 0; i < length; i++) {
                this._buttonLabels[i].text = this._buttonLabelsText[this._list.pageIndex];
            }
        }
    }

    public destroy():void {
        super.destroy();
    }
}
