import {BeSkill} from '@be/be-framework';

export default class Analytics {
    private skill:BeSkill;

    constructor(skill:BeSkill) {
        this.skill = skill;
    }

    public thingsDone(cards_shown:number) {
        this.skill.track('TTD Complete', { cards_shown });
    }

    public cardShown(text:string){
        this.skill.track('TTD Card Shown', { text });
    }
}
