import jibo = require('jibo');
import CardData from './CardData';
import FriendlyTips from './FriendlyTips';


export default class Category {
    public name:string;
    public id:string;
    public background:string;
    public cards:Array<CardData>;
    public rootNode:jibo.kb.Node;
    public log:typeof jibo.log;
    public skill:FriendlyTips;

    constructor(data:any, rootNode:jibo.kb.Node, skill:FriendlyTips){
        this.log = skill.log;
        this.skill = skill;
        this.background = data.background;
        this.name = data.name;
        this.id = data.id;
        this.cards = [];
        this.rootNode = rootNode;
        for(let card of data.cards){
            let seen = !!this.rootNode.data.seen[this.id][card.id];
            this.cards.push(new CardData(card, seen, this));
        }
    }

    public get bestCard():CardData{
        let bestCards = [];
        for(let card of this.cards){
            if(card.featured && !card.seen){
                bestCards.push(card);
            }
        }
        if(bestCards.length){
            return this._random(bestCards);
        }
        for(let card of this.cards){
            if(!card.seen){
                bestCards.push(card);
            }
        }
        if(bestCards.length){
            return this._random(bestCards);
        }
        //no best card, just do whatever
        return this._random(this.cards);
    }

    public destroy(){
        this.background = null;
        this.name = null;
        this.id = null;
        for(let card of this.cards){
            card.destroy();
            card = null;
        }
        this.cards = null;
        this.log = null;
        this.skill = null;
    }

    private _random(arr:Array<CardData>):CardData{
        return arr[Math.floor(Math.random() * arr.length)];
    }
}
